parameters.jsCode:
// Normalize form data for downstream nodes (form field names may vary by n8n version)
const data = $input.first().json;
const body = data.body || data;
return [{
  json: {
    event_name: body.event_name || body.eventName || '',
    event_date: body.event_date || body.eventDate || '',
    organizer_name: body.organizer_name || body.organizerName || '',
    organizer_email: body.organizer_email || body.organizerEmail || '',
    audience_size: parseInt(body.audience_size || body.audienceSize || 0) || 0,
    key_topics: body.key_topics || body.keyTopics || '',
    notable_reactions: body.notable_reactions || body.notableReactions || '',
    talk_recording_url: body.talk_recording_url || body.talkRecordingUrl || '',
    attendee_list_available: !!body.attendee_list_available || !!body.attendeeListAvailable
  }
}];

values.content:
=Write thank you email for:

Event: {{ $json.event_name }}
Date: {{ $json.event_date }}
Organizer: {{ $json.organizer_name }} ({{ $json.organizer_email }})
Key topics: {{ $json.key_topics }}
Notable reactions: {{ $json.notable_reactions }}

Template structure:
1. Thank them for opportunity
2. Share 1-2 positive attendee comments (use notable_reactions if provided)
3. Ask: "Would you be willing to provide a short testimonial?"
4. Ask: "Know of other events that might benefit from this content?"
5. Offer to stay connected

Tone: Grateful, professional, not pushy.

